body.script:
//
(function(){
'use strict';

/* ========================================================================
 *  Qamhad Live — Blogger SPA. Talks ONLY to the API server.
 * ====================================================================== */
var API = (document.querySelector('meta[name="qamhad:api"]')||{}).content || 'https://api.qamhad.com';
API = API.replace(/\/+$/,'');
var LANG = (document.documentElement.lang||'ar').indexOf('en')===0 ? 'en' : 'ar';
var RTL = LANG === 'ar';

var PH = {
  team:'data:image/svg+xml;utf8,<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 64 64"><rect width="64" height="64" rx="12" fill="%23e2e8f0"/><path d="M32 14l14 6v10c0 9-6 15-14 18-8-3-14-9-14-18V20z" fill="%2394a3b8"/></svg>',
  player:'data:image/svg+xml;utf8,<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 64 64"><rect width="64" height="64" rx="12" fill="%23e2e8f0"/><circle cx="32" cy="24" r="11" fill="%2394a3b8"/><path d="M12 56c2-12 10-18 20-18s18 6 20 18z" fill="%2394a3b8"/></svg>',
  news:'data:image/svg+xml;utf8,<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 160 90"><rect width="160" height="90" fill="%23e2e8f0"/><path d="M40 55l18-20 16 16 12-12 34 36H40z" fill="%2394a3b8"/><circle cx="52" cy="30" r="8" fill="%23cbd5e1"/></svg>'
};

/* ---------- tiny DOM helpers ---------- */
function el(html){var d=document.createElement('div');d.innerHTML=html.trim();return d.firstChild;}
function esc(s){return String(s==null?'':s).replace(/[&<>"']/g,function(c){return{'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#39;'}[c];});}
function $(s,r){return (r||document).querySelector(s);}
function q(name,d){var m=new RegExp('[?&]'+name+'=([^&]*)').exec(location.search);return m?decodeURIComponent(m[1].replace(/\+/g,' ')):(d||'');}
function ymd(d){return d.getFullYear()+'-'+String(d.getMonth()+1).padStart(2,'0')+'-'+String(d.getDate()).padStart(2,'0');}
function toast(msg){var t=$('#toast');t.textContent=msg;t.classList.add('show');clearTimeout(t._t);t._t=setTimeout(function(){t.classList.remove('show');},2600);}

/* ---------- API fetch ---------- */
var _cache={};
function api(path,opts){
  var url=API+'/'+path.replace(/^\//,'');
  url+=(url.indexOf('?')===-1?'?':'&')+'lang='+LANG;
  return fetch(url,{headers:{'Accept':'application/json'},credentials:'omit'}).then(function(r){return r.json();});
}
function apiCached(path,ttl){
  var k=path,now=Date.now();
  if(_cache[k] && now-_cache[k].t < (ttl||30000)) return Promise.resolve(_cache[k].v);
  return api(path).then(function(v){_cache[k]={t:now,v:v};return v;});
}

/* ---------- media URL builder (mirrors server media_url) ---------- */
function media(kind,size,file,fb){
  fb=fb||PH[kind]||PH.team;
  if(!file) return fb;
  if(/(^|\/)[a-z0-9_]*default\.(png|jpe?g|gif|webp)$/i.test(file)) return fb;
  if(/^https?:\/\//i.test(file)){
    try{var u=new URL(file);if(u.host.indexOf('imgs.')===0) return API+'/media'+u.pathname;}catch(e){}
    return file;
  }
  file=String(file).replace(/^\/+/,'');
  if(!/^[A-Za-z0-9._-]+$/.test(file)) return fb;
  return API+'/media/'+kind+'/'+size+'/'+file;
}
function teamImg(t,s){var f=t&&(t.image||t.logo);return media('teams',s||'64',f,PH.team);}
function leagueImg(l,s){var f=l&&l.image;return media('championship',s||'128',f,PH.team);}
function playerImg(p,s){var f=p&&p.image;return media('player',s||'64',f,PH.player);}
function newsImg(n,s){var f=n&&n.image;return media('news',s||'640',f,PH.news);}
function tname(t){if(!t)return '—';if(typeof t==='string')return t;return t.title||t.full_title||t.name||t.short_title||t.team_name||'—';}
function pname(p){if(!p)return '';if(typeof p==='string')return p;return p.name||p.full_name||p.title||'';}

/* ---------- match state (mirrors server) ---------- */
function matchState(m){
  var st=+(m.status||0), live=+(m.live||0);
  if(st===4) return {key:'finished',label:LANG==='en'?'Ended':'انتهت'};
  if(live===1 || [1,2,3,5,6,7,8,13].indexOf(st)>=0){
    var lbl=liveLabel(m,st);
    return {key:'live',label:lbl};
  }
  return {key:'upcoming',label:fmtTime(m.match_time)};
}
function liveLabel(m,st){
  if(st===2) return LANG==='en'?'HT':"استراحة";
  if([7,8,13].indexOf(st)>=0) return LANG==='en'?'PENS':'ركلات';
  var base={1:0,3:45,5:90,6:105}[st]||0, cap={1:45,3:90,5:105,6:120}[st]||45;
  var start=(+m.ht_time>1e9)?+m.ht_time:0, minute;
  if(start>0) minute=base+Math.floor(Math.max(0,Date.now()/1000-start)/60)+1;
  else if(+m.minutes>0 && +m.minutes<=130) minute=+m.minutes;
  else minute=base+1;
  return minute>cap?(cap+'+'+(minute-cap)+"'"):(minute+"'");
}
function fmtTime(t){t=(t||'').trim();if(!t)return '';var d=new Date('2000-01-01T'+ (t.length<=5?t+':00':t));if(isNaN(d))return t;
  var h=d.getHours(),m=String(d.getMinutes()).padStart(2,'0'),ap=h>=12?(LANG==='en'?'PM':'م'):(LANG==='en'?'AM':'ص');h=h%12||12;return String(h).padStart(2,'0')+':'+m+' '+ap;}
function fmtDate(v){if(!v)return '';var d=new Date((''+v).length<=10?v+'T00:00:00':v);if(isNaN(d))return '';
  return d.toLocaleDateString(LANG==='en'?'en-GB':'ar-EG',{weekday:'short',day:'numeric',month:'short',year:'numeric'});}

/* ---------- skeletons ---------- */
function skCards(n){var h='';for(var i=0;i<(n||6);i++)h+='<div class="sk sk-card"></div>';return '<div class="grid cards">'+h+'</div>';}
function skList(n){var h='';for(var i=0;i<(n||6);i++)h+='<div class="sk sk-card" style="height:110px"></div>';return '<div class="grid news">'+h+'</div>';}
function loading(){return '<div class="section-head"><div class="sk sk-line" style="width:160px;height:22px"></div></div>'+skCards(6);}

/* ==================== COMPONENTS ==================== */
function matchCard(m){
  var s=matchState(m), lg=m.championship||{}, home=m.home_team_info||m.home_team||{}, away=m.away_team_info||m.away_team||{};
  var id=m.match_id, started=s.key!=='upcoming';
  var badge = s.key==='live'?'<span class="badge live"><span class="dot"></span>'+esc(s.label)+'</span>'
    : s.key==='finished'?'<span class="badge fin">'+esc(s.label)+'</span>'
    : '<span class="badge up"><i class="bi bi-clock"></i> '+esc(s.label)+'</span>';
  var mid = started
    ? '<div class="score">'+(+m.home_scores||0)+' <span class="vs">-</span> '+(+m.away_scores||0)+'</div>'
    : '<div class="vs" style="font-size:20px">'+ (LANG==='en'?'VS':'ضد') +'</div>';
  var watch = m.watchable||s.key==='live' ? '<a class="watch" href="?view=match&amp;id='+id+'"><i class="bi bi-play-circle"></i> '+(LANG==='en'?'Match center':'مركز المباراة')+'</a>' : '';
  return '<a class="match" href="?view=match&amp;id='+id+'">'
    +'<div class="lg"><img loading="lazy" src="'+leagueImg(lg,'64')+'" alt=""/> '+esc(lg.title||'')+' <span style="margin-inline-start:auto">'+badge+'</span></div>'
    +'<div class="row">'
    +'<div class="team"><img loading="lazy" src="'+teamImg(home)+'" alt="'+esc(tname(home))+'"/>'+esc(tname(home))+'</div>'
    +'<div class="mid">'+mid+'</div>'
    +'<div class="team"><img loading="lazy" src="'+teamImg(away)+'" alt="'+esc(tname(away))+'"/>'+esc(tname(away))+'</div>'
    +'</div>'+watch+'</a>';
}
function newsCard(n){
  return '<a class="news-card" href="?view=news&amp;id='+n.id+'">'
    +'<img class="thumb" loading="lazy" src="'+newsImg(n)+'" alt="'+esc(n.title)+'"/>'
    +'<div class="body"><h3>'+esc(n.title)+'</h3>'
    +'<div class="meta"><i class="bi bi-clock"></i> '+esc(fmtDate(n.created_at||n.date||''))+'</div></div></a>';
}
function leagueCard(l){
  return '<a class="league-card" href="?view=league&amp;id='+(l.url_id||l.id)+'">'
    +'<img loading="lazy" src="'+leagueImg(l)+'" alt="'+esc(l.title||l.ar||'')+'"/>'
    +'<span>'+esc(l.title||l.ar||l.en||'')+'</span></a>';
}
function videoCard(v){
  var yt=v.youtube_id;
  return '<div class="video-card" data-yt="'+esc(yt||'')+'" data-url="'+esc(v.video_url||'')+'">'
    +'<div class="thumb"><img loading="lazy" src="'+esc(v.thumbnail||PH.news)+'" alt="'+esc(v.title)+'"/><span class="play"><i class="bi bi-play-circle-fill"></i></span></div>'
    +'<div class="body"><h3>'+esc(v.title)+'</h3></div></div>';
}
function empty(msg,icon){return '<div class="empty"><i class="bi bi-'+(icon||'inbox')+'"></i>'+esc(msg)+'</div>';}
function head(title,icon,moreHref,moreTxt){
  return '<div class="section-head"><i class="bi bi-'+icon+'"></i><h2>'+esc(title)+'</h2>'
    +(moreHref?'<a class="more" href="'+moreHref+'">'+esc(moreTxt||(LANG==='en'?'All':'الكل'))+' <i class="bi bi-chevron-'+(RTL?'left':'right')+'"></i></a>':'')+'</div>';
}

/* ==================== PAGES ==================== */
var app=$('#app'), SET={};

function setMeta(title,desc){
  document.title=title;
  var m=$('meta[name="description"]');if(m&&desc)m.content=desc;
  var c=$('link[rel="canonical"]');if(!c){c=el('<link rel="canonical"/>');document.head.appendChild(c);}
  c.href=location.href;
}
function jsonld(obj){
  var old=$('#ld-dyn');if(old)old.remove();
  var s=document.createElement('script');s.type='application/ld+json';s.id='ld-dyn';s.textContent=JSON.stringify(obj);document.head.appendChild(s);
}

var Pages={};

Pages.home=function(){
  app.innerHTML='<div class="hero"><h1>'+esc(SET.site?SET.site['name_'+LANG]:'قمهد لايف')+'</h1><p>'+esc(SET.site?SET.site['slogan_'+LANG]:'')+'</p></div>'+loading();
  setMeta((SET.site?SET.site['name_'+LANG]:'Qamhad Live'),(SET.site?SET.site['slogan_'+LANG]:''));
  var today=ymd(new Date());
  Promise.all([apiCached('matches.php?date='+today,60000),apiCached('news.php?page=1',300000),apiCached('league.php',3600000)])
  .then(function(r){
    var matches=(r[0].data)||[], news=r[1].data||{}, leagues=(r[2].data)||[];
    var live=matches.filter(function(m){return matchState(m).key==='live';});
    var html='<div class="hero"><h1>'+esc(SET.site['name_'+LANG])+'</h1><p>'+esc(SET.site['slogan_'+LANG])+'</p></div>';
    html+=adSlot('header');
    if(live.length){html+=head(LANG==='en'?'Live now':'مباشر الآن','broadcast','?view=live');html+='<div class="grid cards">'+live.slice(0,6).map(matchCard).join('')+'</div>';}
    html+=head(LANG==='en'?"Today's matches":'مباريات اليوم','calendar-event','?view=matches');
    html+= matches.length?'<div class="grid cards">'+matches.slice(0,8).map(matchCard).join('')+'</div>':empty(LANG==='en'?'No matches today':'لا توجد مباريات اليوم','calendar-x');
    html+=adSlot('infeed');
    if(leagues.length){html+=head(LANG==='en'?'Leagues':'البطولات','trophy','?view=leagues');html+='<div class="grid leagues">'+leagues.slice(0,12).map(leagueCard).join('')+'</div>';}
    var items=news.items||[];
    if(news.featured)items=[news.featured].concat(items);
    if(items.length){html+=head(LANG==='en'?'Latest news':'آخر الأخبار','newspaper','?view=news');html+='<div class="grid news">'+items.slice(0,6).map(newsCard).join('')+'</div>';}
    app.innerHTML=html;
    jsonld({"@context":"https://schema.org","@type":"WebSite","name":SET.site['name_'+LANG],"url":SET.site.blog_url,"potentialAction":{"@type":"SearchAction","target":SET.site.blog_url+"/?view=search&q={q}","query-input":"required name=q"}});
  }).catch(function(){app.innerHTML=empty(LANG==='en'?'Failed to load':'تعذّر التحميل','wifi-off');});
};

Pages.live=function(){
  app.innerHTML=head(LANG==='en'?'Live matches':'المباريات المباشرة','broadcast')+skCards(6);
  setMeta((LANG==='en'?'Live matches':'مباريات مباشرة')+' — '+SET.site['name_'+LANG]);
  api('live.php').then(function(r){
    var m=r.data||[];
    app.innerHTML=head(LANG==='en'?'Live matches':'المباريات المباشرة','broadcast')
      +(m.length?'<div class="grid cards">'+m.map(matchCard).join('')+'</div>':empty(LANG==='en'?'No live matches right now':'لا توجد مباريات مباشرة حالياً','broadcast'));
  });
};

Pages.matches=function(){
  var day=q('day')||'today';
  var dates={yesterday:-1,today:0,tomorrow:1};
  var tabs=[['yesterday',LANG==='en'?'Yesterday':'أمس'],['today',LANG==='en'?'Today':'اليوم'],['tomorrow',LANG==='en'?'Tomorrow':'غداً']];
  var d=new Date();d.setDate(d.getDate()+(dates[day]||0));
  var html=head(LANG==='en'?'Matches':'المباريات','calendar-event');
  html+='<div class="tabs">'+tabs.map(function(t){return '<a class="tab '+(t[0]===day?'active':'')+'" href="?view=matches&amp;day='+t[0]+'">'+t[1]+'</a>';}).join('')+'</div><div id="mlist">'+skCards(6)+'</div>';
  app.innerHTML=html;
  setMeta((LANG==='en'?'Matches':'المباريات')+' — '+SET.site['name_'+LANG]);
  api('matches.php?date='+ymd(d)).then(function(r){
    var m=r.data||[];
    $('#mlist').innerHTML= m.length?'<div class="grid cards">'+m.map(matchCard).join('')+'</div>':empty(LANG==='en'?'No matches':'لا توجد مباريات','calendar-x');
  });
};

Pages.match=function(){
  var id=q('id');if(!id)return go('home');
  app.innerHTML=loading();
  api('match.php?id='+id).then(function(r){
    var d=r.data;if(!d||!d.info)return void(app.innerHTML=empty(LANG==='en'?'Match not found':'لم يتم العثور على المباراة','calendar-x'));
    var m=d.info,s=d.state||matchState(m),home=m.home_team_info||m.home_team||{},away=m.away_team_info||m.away_team||{},lg=m.championship||{};
    var started=s.key!=='upcoming';
    setMeta(tname(home)+' '+(LANG==='en'?'vs':'ضد')+' '+tname(away)+' — '+SET.site['name_'+LANG],(lg.title||''));
    var html='<div class="card pad" style="margin-top:6px">'
      +'<div class="lg" style="justify-content:center;margin-bottom:14px"><img src="'+leagueImg(lg,'64')+'" style="width:20px;height:20px"/> '+esc(lg.title||'')+'</div>'
      +'<div class="row" style="display:grid;grid-template-columns:1fr auto 1fr;align-items:center;gap:10px">'
      +'<div class="team" style="display:flex;flex-direction:column;align-items:center;gap:8px"><a href="?view=team&amp;id='+((home.row_id)||(home.id)||'')+'"><img src="'+teamImg(home,'128')+'" style="width:72px;height:72px"/></a><b>'+esc(tname(home))+'</b></div>'
      +'<div style="text-align:center"><div class="score" style="font-size:34px;font-weight:800">'+(started?((+m.home_scores||0)+' - '+(+m.away_scores||0)):(LANG==='en'?'VS':'ضد'))+'</div>'
      +'<div style="margin-top:6px">'+(s.key==='live'?'<span class="badge live"><span class="dot"></span>'+esc(s.label)+'</span>':'<span class="badge '+(s.key==='finished'?'fin':'up')+'">'+esc(s.label||fmtTime(m.match_time))+'</span>')+'</div></div>'
      +'<div class="team" style="display:flex;flex-direction:column;align-items:center;gap:8px"><a href="?view=team&amp;id='+((away.row_id)||(away.id)||'')+'"><img src="'+teamImg(away,'128')+'" style="width:72px;height:72px"/></a><b>'+esc(tname(away))+'</b></div>'
      +'</div></div>';
    // channels
    if(d.channels&&d.channels.length){
      html+=head(LANG==='en'?'Watch':'المشاهدة','play-btn');
      html+='<div class="grid" style="grid-template-columns:repeat(auto-fill,minmax(160px,1fr))">'
        +d.channels.map(function(c,i){return '<button class="btn ghost play-ch" data-idx="'+i+'"><i class="bi bi-play-circle"></i> '+esc(c.name)+'</button>';}).join('')+'</div>';
      window._chans=d.channels;
    }
    // events
    var evs=d.events||[];
    if(evs.length){
      html+=head(LANG==='en'?'Events':'الأحداث','clock-history');
      html+='<div class="card pad">'+evs.map(eventRow).join('')+'</div>';
    }
    // stats
    if(d.stats&&(d.stats.length||Object.keys(d.stats).length)){
      html+=head(LANG==='en'?'Statistics':'الإحصائيات','bar-chart');
      html+='<div class="card pad">'+statBars(d.stats)+'</div>';
    }
    // lineups
    var lu=d.lineup&&d.lineup.lineup;
    if(lu&&Object.keys(lu).length){
      html+=head(LANG==='en'?'Lineups':'التشكيلة','people');
      html+='<div class="card pad">'+lineups(lu)+'</div>';
    }
    html+=commentsBlock('/match/'+id);
    app.innerHTML=html;
    jsonld({"@context":"https://schema.org","@type":"SportsEvent","name":tname(home)+' vs '+tname(away),"sport":"Soccer","homeTeam":{"@type":"SportsTeam","name":tname(home)},"awayTeam":{"@type":"SportsTeam","name":tname(away)},"startDate":(m.match_date||'')+ (m.match_time?('T'+m.match_time):'')});
    bindComments('/match/'+id);
    if(s.key==='live') schedulePoll(function(){if(current.view==='match'&&current.id===id)Pages.match();},60000);
  });
};
function eventRow(ev){
  var icons={goal:'bi-dribbble',yellow:'bi-square-fill',red:'bi-square-fill',sub:'bi-arrow-left-right',penalty:'bi-dribbble'};
  var t=(ev.event||ev.type||'').toLowerCase();
  var ic=t.indexOf('goal')>=0?'bi-dribbble':t.indexOf('yellow')>=0?'bi-square-fill':t.indexOf('red')>=0?'bi-square-fill':t.indexOf('sub')>=0?'bi-arrow-left-right':'bi-circle';
  var col=t.indexOf('yellow')>=0?'#f59e0b':t.indexOf('red')>=0?'#ef4444':'var(--primary)';
  var min=(ev.time_minute||ev.minute||'')+(ev.time_plus?('+'+ev.time_plus):'');
  var who=pname(ev.player_name||ev.player);
  return '<div class="event"><span class="min">'+esc(min)+"'</span><i class=\"bi "+ic+'" style="color:'+col+'"></i><span>'+esc(who||ev.event||'')+'</span></div>';
}
function statBars(stats){
  var arr=Array.isArray(stats)?stats:Object.keys(stats).map(function(k){return stats[k];});
  return arr.map(function(s){
    var h=+(s.home||s.home_value||s.first||0),a=+(s.away||s.away_value||s.second||0),tot=h+a||1;
    var lab=s.name||s.title||s.type||'';
    return '<div class="bar-row"><div style="text-align:end;font-weight:800">'+esc(h)+'</div><div class="lab">'+esc(lab)+'</div><div style="font-weight:800">'+esc(a)+'</div></div>'
      +'<div class="bar"><i style="width:'+Math.round(h/tot*100)+'%"></i></div>';
  }).join('');
}
function lineups(lu){
  return Object.keys(lu).map(function(tid){
    var side=lu[tid],list=(side.lineup||[]);
    return '<div style="margin-bottom:12px"><b>'+esc(side.formation||'')+'</b><div style="display:grid;grid-template-columns:repeat(auto-fill,minmax(120px,1fr));gap:6px;margin-top:8px">'
      +list.map(function(p){var pl=p.player||{};return '<div style="display:flex;gap:6px;align-items:center;font-size:12.5px"><span class="pos">'+(p.shirt_number||p.number||'')+'</span>'+esc(pname(pl))+'</div>';}).join('')+'</div></div>';
  }).join('');
}

Pages.leagues=function(){
  app.innerHTML=head(LANG==='en'?'Leagues':'البطولات','trophy')+'<div class="grid leagues">'+skCards(12)+'</div>';
  setMeta((LANG==='en'?'Leagues':'البطولات')+' — '+SET.site['name_'+LANG]);
  api('league.php').then(function(r){
    var l=r.data||[];
    app.innerHTML=head(LANG==='en'?'Leagues':'البطولات','trophy')+(l.length?'<div class="grid leagues">'+l.map(leagueCard).join('')+'</div>':empty('—'));
  });
};

Pages.league=function(){
  var id=q('id');if(!id)return go('leagues');
  app.innerHTML=loading();
  api('league.php?id='+id).then(function(r){
    var d=r.data||{},lg=d.league||{};
    setMeta((lg.title||'League')+' — '+SET.site['name_'+LANG]);
    var html=head(lg.title||(LANG==='en'?'League':'البطولة'),'trophy');
    html+= d.standings&&d.standings.length? standingsTable(d.standings) : '';
    if(d.scorers&&d.scorers.length){html+=head(LANG==='en'?'Top scorers':'الهدافون','star');html+=scorersTable(d.scorers);}
    if(d.news&&d.news.length){html+=head(LANG==='en'?'News':'الأخبار','newspaper');html+='<div class="grid news">'+d.news.map(newsCard).join('')+'</div>';}
    app.innerHTML=html||empty('—');
  });
};

Pages.standings=function(){
  var id=q('id')|| (SET.featured_leagues&&SET.featured_leagues[1]&&SET.featured_leagues[1].id) || 900326;
  app.innerHTML='<div id="stab"></div>'+loading();
  var tabs=(SET.featured_leagues||[]).slice(0,8);
  var th='<div class="tabs">'+tabs.map(function(l){return '<a class="tab '+(''+l.id===''+id?'active':'')+'" href="?view=standings&amp;id='+l.id+'">'+esc(l[LANG]||l.ar)+'</a>';}).join('')+'</div>';
  setMeta((LANG==='en'?'Standings':'الترتيب')+' — '+SET.site['name_'+LANG]);
  api('standings.php?league='+id).then(function(r){
    var d=r.data||{};
    app.innerHTML=head(LANG==='en'?'Standings':'ترتيب الدوري','list-ol')+th+(d.standings&&d.standings.length?standingsTable(d.standings):empty(LANG==='en'?'No table':'لا يوجد ترتيب'));
  });
};
function standingsTable(rows){
  var h='<div class="table-wrap"><table class="tbl"><thead><tr>'
    +'<th>#</th><th class="team-cell" style="text-align:start">'+(LANG==='en'?'Team':'الفريق')+'</th><th>'+(LANG==='en'?'P':'لعب')+'</th><th>'+(LANG==='en'?'W':'ف')+'</th><th>'+(LANG==='en'?'D':'ت')+'</th><th>'+(LANG==='en'?'L':'خ')+'</th><th>'+(LANG==='en'?'GD':'الفرق')+'</th><th>'+(LANG==='en'?'Pts':'نقاط')+'</th></tr></thead><tbody>';
  rows.forEach(function(r,i){
    var t=r.team_name||{title:r.team_title,image:r.team_image};
    h+='<tr><td><span class="pos">'+(r.ranking||r.rank||i+1)+'</span></td>'
      +'<td class="team-cell"><a href="?view=team&amp;id='+(r.team_id||'')+'"><span><img src="'+teamImg(t)+'"/>'+esc(tname(t))+'</span></a></td>'
      +'<td>'+(r.play||r.played||0)+'</td><td>'+(r.win||0)+'</td><td>'+(r.draw||0)+'</td><td>'+(r.lose||r.loss||0)+'</td>'
      +'<td>'+((+r.goal_for||0)-(+r.goal_against||0))+'</td><td><b style="color:var(--primary)">'+(r.point||r.points||0)+'</b></td></tr>';
  });
  return h+'</tbody></table></div>';
}
function scorersTable(list){
  var h='<div class="table-wrap"><table class="tbl"><thead><tr><th>#</th><th class="team-cell" style="text-align:start">'+(LANG==='en'?'Player':'اللاعب')+'</th><th>'+(LANG==='en'?'Goals':'أهداف')+'</th></tr></thead><tbody>';
  list.forEach(function(s,i){
    var p=s.player_info||s.player||{};
    h+='<tr><td><span class="pos">'+(i+1)+'</span></td><td class="team-cell"><a href="?view=player&amp;id='+((p.row_id)||(p.id)||'')+'"><span><img src="'+playerImg(p)+'"/>'+esc(pname(p))+'</span></a></td><td><b style="color:var(--primary)">'+(s.goals||s.goal||s.count||0)+'</b></td></tr>';
  });
  return h+'</tbody></table></div>';
}

