function squadBlock(sq){
  var groups=['G','D','M','F'],labels={G:LANG==='en'?'Goalkeepers':'حراس',D:LANG==='en'?'Defenders':'دفاع',M:LANG==='en'?'Midfield':'وسط',F:LANG==='en'?'Attack':'هجوم'};
  if(Array.isArray(sq)){return '<div class="grid" style="grid-template-columns:repeat(auto-fill,minmax(130px,1fr))">'+sq.map(playerMini).join('')+'</div>';}
  var h='';groups.forEach(function(g){var list=sq[g]||[];if(!list.length)return;
    h+='<div class="section-head" style="margin:14px 0 8px"><h2 style="font-size:15px">'+labels[g]+'</h2></div>';
    h+='<div class="grid" style="grid-template-columns:repeat(auto-fill,minmax(130px,1fr))">'+list.map(playerMini).join('')+'</div>';
  });
  return h;
}
function playerMini(p){
