    var vitals=[['البلد','country_title','Country'],['العمر','age','Age'],['الطول','height','Height'],['القيمة','market_value','Value'],['القدم','foot','Foot'],['الرقم','shirt_number','No.']];
    var vh=vitals.map(function(v){var val=info[v[1]];return val?'<div class="stat-box"><b style="font-size:15px">'+esc(val)+'</b><span>'+(LANG==='en'?v[2]:v[0])+'</span></div>':'';}).join('');
