        +stats.map(function(s){return '<tr><td class="team-cell">'+esc(s.championship||s.league||s.competition||'')+'</td><td>'+(s.matches||s.apps||s.played||0)+'</td><td>'+(s.goals||0)+'</td><td>'+(s.assists||s.assist||0)+'</td></tr>';}).join('')+'</tbody></table></div>';
