Pages.news=function(){
  app.innerHTML=head(LANG==='en'?'News':'الأخبار','newspaper')+'<div id="nlist">'+skList(6)+'</div>';
  setMeta((LANG==='en'?'News':'الأخبار')+' — '+SET.site['name_'+LANG]);
  var page=1,busy=false,done=false;
  function load(){
    if(busy||done)return;busy=true;
    api('news.php?page='+page).then(function(r){
      var d=r.data||{},items=d.items||[];
      if(page===1&&d.featured)items=[d.featured].concat(items);
      var grid=$('#nlist');
      if(page===1)grid.innerHTML='<div class="grid news" id="ngrid"></div>';
      var g=$('#ngrid');
      items.forEach(function(n){g.appendChild(el(newsCard(n)));});
      if(!items.length||(d.last_page&&page>=d.last_page))done=true;
      page++;busy=false;
      if(done)g.insertAdjacentHTML('afterend','');
    }).catch(function(){busy=false;});
  }
  load();
  attachInfinite(load);
};

Pages.news_item=function(){
  var id=q('id');if(!id)return go('news');
  app.innerHTML=loading();
  api('news-details.php?id='+id).then(function(r){
    var n=r.data;if(!n||!n.title)return void(app.innerHTML=empty(LANG==='en'?'Article not found':'الخبر غير متوفر','file-earmark-x'));
    setMeta(n.title+' — '+SET.site['name_'+LANG],(n.news_desc||'').slice(0,160));
    var body=n.full_news||n.news_desc||'';
    var html='<article class="card" style="margin-top:6px"><img class="thumb" style="width:100%;aspect-ratio:16/9;object-fit:cover" src="'+newsImg(n,'1200')+'"/>'
      +'<div class="pad"><h1 style="font-size:22px;margin:6px 0 8px">'+esc(n.title)+'</h1>'
      +'<div class="meta" style="color:var(--muted);font-size:12.5px;margin-bottom:12px"><i class="bi bi-clock"></i> '+esc(fmtDate(n.created_at))+'</div>'
      +'<div class="article-body" style="font-size:15.5px;line-height:1.9">'+sanitize(body)+'</div></div></article>';
    html+=adSlot('article');
    html+=commentsBlock('/news/'+id);
    app.innerHTML=html;
    bindComments('/news/'+id);
    jsonld({"@context":"https://schema.org","@type":"NewsArticle","headline":n.title,"image":[newsImg(n,'1200')],"datePublished":n.created_at||'',"author":{"@type":"Organization","name":SET.site['name_'+LANG]},"publisher":{"@type":"Organization","name":SET.site['name_'+LANG]}});
  });
};
function sanitize(html){
  var d=document.createElement('div');d.innerHTML=html||'';
  d.querySelectorAll('script,style,iframe,object,embed,link,meta').forEach(function(n){n.remove();});
  d.querySelectorAll('*').forEach(function(n){for(var i=n.attributes.length-1;i>=0;i--){var a=n.attributes[i].name;if(/^on/i.test(a)||a==='srcset')n.removeAttribute(a);}});
  return d.innerHTML;
}

