/* ==================== Comments ==================== */
function commentsBlock(path){
  return head(LANG==='en'?'Comments':'التعليقات','chat-dots')
    +'<div class="card pad"><div id="cList">'+skList(2)+'</div>'
    +'<div style="display:grid;gap:8px;margin-top:12px">'
    +'<input id="cName" placeholder="'+(LANG==='en'?'Your name':'اسمك')+'" style="padding:10px;border-radius:10px;border:1px solid var(--border);background:var(--surface-2);color:var(--text)"/>'
    +'<textarea id="cBody" rows="3" placeholder="'+(LANG==='en'?'Write a comment...':'اكتب تعليقاً...')+'" style="padding:10px;border-radius:10px;border:1px solid var(--border);background:var(--surface-2);color:var(--text)"></textarea>'
    +'<button class="btn" id="cSend" style="justify-content:center"><i class="bi bi-send"></i> '+(LANG==='en'?'Send':'إرسال')+'</button></div></div>';
}
function bindComments(path){
  function render(list){
    var box=$('#cList');if(!box)return;
    box.innerHTML=list.length?list.map(function(c){return '<div style="padding:10px 0;border-bottom:1px solid var(--border)"><b>'+esc(c.name)+'</b> <span style="color:var(--muted);font-size:11.5px">'+esc(fmtDate(c.at))+'</span><div>'+esc(c.body)+'</div></div>';}).join(''):empty(LANG==='en'?'Be the first to comment':'كن أول من يعلّق','chat');
  }
  api('comments.php?path='+encodeURIComponent(path)).then(function(r){render((r.data&&r.data.comments)||[]);});
  var btn=$('#cSend');if(btn)btn.onclick=function(){
    var name=$('#cName').value.trim(),body=$('#cBody').value.trim();
    if(body.length<2)return toast(LANG==='en'?'Comment too short':'التعليق قصير جداً');
    fetch(API+'/comments.php?lang='+LANG,{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({path:path,name:name,body:body})})
      .then(function(r){return r.json();}).then(function(r){
        if(r.ok){$('#cBody').value='';toast(LANG==='en'?'Comment added':'تم إضافة التعليق');api('comments.php?path='+encodeURIComponent(path)).then(function(r){render((r.data&&r.data.comments)||[]);});}
        else toast(r.error||'Error');
      }).catch(function(){toast('Error');});
  };
}

/* ==================== Ads ==================== */
function adSlot(kind){
  var cfg=SET.ads||{};if(!cfg.adsense_client)return '';
  var slot=cfg['slot_'+(kind==='infeed'?'infeed':kind==='article'?'article':'header')]||'';
  if(!slot)return '';
  return '<div class="ad-slot"><ins class="adsbygoogle" style="display:block" data-ad-client="'+esc(cfg.adsense_client)+'" data-ad-slot="'+esc(slot)+'" data-ad-format="auto" data-full-width-responsive="true"></ins></div>';
}
function pushAds(){try{document.querySelectorAll('.adsbygoogle:not([data-done])').forEach(function(ins){ins.setAttribute('data-done','1');(window.adsbygoogle=window.adsbygoogle||[]).push({});});}catch(e){}}

/* ==================== Player (video + HLS) ==================== */
function openPlayer(mount){var m=$('#playerModal');$('#playerMount').innerHTML=mount;m.classList.add('open');}
function closePlayer(){var m=$('#playerModal');m.classList.remove('open');$('#playerMount').innerHTML='';}
function playYouTube(id){openPlayer('<iframe allow="autoplay;encrypted-media;fullscreen" allowfullscreen="" src="https://www.youtube.com/embed/'+esc(id)+'?autoplay=1"></iframe>');}
function playStream(src){
  openPlayer('<video id="hlsV" controls autoplay playsinline></video>');
  var v=$('#hlsV');
  if(!src||!src.url){return;}
  if(src.type==='m3u8'||/\.m3u8/.test(src.url)){
    if(v.canPlayType('application/vnd.apple.mpegurl')){v.src=src.url;}
    else{loadScript('https://cdn.jsdelivr.net/npm/hls.js@1.5.13/dist/hls.min.js',function(){
      if(window.Hls&&Hls.isSupported()){var h=new Hls();h.loadSource(src.url);h.attachMedia(v);}else v.src=src.url;
    });}
  }else{v.src=src.url;}
}
function loadScript(u,cb){var s=document.createElement('script');s.src=u;s.onload=cb;s.onerror=cb;document.head.appendChild(s);}

document.addEventListener('click',function(e){
  var pc=e.target.closest('.play-ch');
  if(pc&&window._chans){var c=window._chans[+pc.dataset.idx];if(c)playStream(c);return;}
  var vc=e.target.closest('.video-card');
  if(vc){var yt=vc.dataset.yt;if(yt)playYouTube(yt);else if(vc.dataset.url)window.open(vc.dataset.url,'_blank');return;}
  var tv=e.target.closest('.play-tv');
  if(tv){var slug=tv.dataset.slug;toast(LANG==='en'?'Loading channel...':'جارٍ تحميل القناة...');
    api('channel.php?slug='+encodeURIComponent(slug)).then(function(r){var s=r.data&&r.data.sources&&r.data.sources[0];if(s)playStream(s);else toast(LANG==='en'?'Channel unavailable':'القناة غير متوفرة');});return;}
});

/* ==================== Search ==================== */
function openSearch(){$('#searchPanel').classList.add('open');setTimeout(function(){$('#searchInput').focus();},250);renderHistory();}
function closeSearch(){$('#searchPanel').classList.remove('open');}
function history(){try{return JSON.parse(localStorage.getItem('q_hist')||'[]');}catch(e){return [];}}
function pushHistory(term){var h=history().filter(function(t){return t!==term;});h.unshift(term);h=h.slice(0,8);localStorage.setItem('q_hist',JSON.stringify(h));}
function renderHistory(){
  var h=history();
  $('#searchResults').innerHTML=h.length?('<div style="color:var(--muted);font-weight:700;margin-bottom:8px">'+(LANG==='en'?'Recent':'عمليات بحث سابقة')+'</div>'+h.map(function(t){return '<div class="suggest hist" data-term="'+esc(t)+'"><i class="bi bi-clock-history"></i> '+esc(t)+'</div>';}).join('')):'';
}
var _sT;
function doSearch(term){
  if(term.length<2){renderHistory();return;}
  clearTimeout(_sT);_sT=setTimeout(function(){
    $('#searchResults').innerHTML=skList(4);
    api('search.php?q='+encodeURIComponent(term)).then(function(r){
      var d=r.data||{},players=d.players||[],teams=d.teams||[];
      var re=new RegExp('('+term.replace(/[.*+?^${}()|[\]\\]/g,'\\$&')+')','gi');
      function hl(s){return esc(s).replace(re,'<span class="mark">$1</span>');}
      var html='';
      teams.forEach(function(t){var tt=t.name||t;html+='<a class="suggest" href="?view=team&id='+((tt.row_id)||(t.row_id)||(t.id)||'')+'"><img src="'+teamImg(tt)+'"/><span>'+hl(tname(tt))+'</span><i class="bi bi-shield" style="margin-inline-start:auto;color:var(--muted)"></i></a>';});
      players.forEach(function(p){var pp=p.name||p;html+='<a class="suggest" href="?view=player&id='+((pp.row_id)||(p.row_id)||(p.id)||'')+'"><img src="'+playerImg(pp)+'"/><span>'+hl(pname(pp))+'</span><i class="bi bi-person" style="margin-inline-start:auto;color:var(--muted)"></i></a>';});
      $('#searchResults').innerHTML=html||empty(LANG==='en'?'No results':'لا نتائج','search');
    });
  },250);
}

/* ==================== Infinite scroll + pull to refresh ==================== */
var _infinite=null;
function attachInfinite(cb){_infinite=cb;}
window.addEventListener('scroll',function(){
  if(!_infinite)return;
  if(window.innerHeight+window.scrollY >= document.body.offsetHeight-600)_infinite();
},{passive:true});

/* pull to refresh (touch) */
(function(){var sy=0,pull=0,active=false;
  window.addEventListener('touchstart',function(e){if(window.scrollY<=0){sy=e.touches[0].clientY;active=true;}},{passive:true});
  window.addEventListener('touchmove',function(e){if(!active)return;pull=e.touches[0].clientY-sy;if(pull>0&&pull<140){$('#ptr').style.height=Math.min(pull,70)+'px';}},{passive:true});
  window.addEventListener('touchend',function(){if(active&&pull>70){_cache={};route();}$('#ptr').style.height='0';active=false;pull=0;},{passive:true});
})();

/* live poll */
var _pollT=null;
function schedulePoll(fn,ms){clearTimeout(_pollT);_pollT=setTimeout(fn,ms);}

/* ==================== Live bar ==================== */
function refreshLiveBar(){
  api('live.php').then(function(r){
    var m=r.data||[],bar=$('#liveBar');
    if(!m.length){bar.innerHTML='';return;}
    bar.innerHTML=m.slice(0,20).map(function(x){var h=x.home_team_info||x.home_team||{},a=x.away_team_info||x.away_team||{};
      return '<a class="live-chip" href="?view=match&id='+x.match_id+'"><span class="dot"></span>'+esc(tname(h))+' '+(+x.home_scores||0)+'-'+(+x.away_scores||0)+' '+esc(tname(a))+'</a>';}).join('');
  }).catch(function(){});
}

/* ==================== Router ==================== */
var current={};
var routes={home:Pages.home,live:Pages.live,matches:Pages.matches,match:Pages.match,leagues:Pages.leagues,league:Pages.league,
  standings:Pages.standings,scorers:Pages.scorers,team:Pages.team,player:Pages.player,news:Pages.news,videos:Pages.videos,
  channels:Pages.channels,search:Pages.search,about:Pages.about,contact:Pages.contact,privacy:Pages.privacy};

function route(){
  _infinite=null;clearTimeout(_pollT);
  var view=q('view')||'home', id=q('id');
  current={view:view,id:id};
  window.scrollTo(0,0);
  var fn;
  if(view==='news'&&id)fn=Pages.news_item;
  else fn=routes[view]||Pages.notfound;
  try{fn();}catch(e){app.innerHTML=empty(LANG==='en'?'Something went wrong':'حدث خطأ ما','exclamation-triangle');}
  setActiveNav(view);
  setTimeout(pushAds,300);
  if(SET.analytics&&SET.analytics.ga4&&window.gtag)gtag('event','page_view',{page_location:location.href,page_title:document.title});
}
function go(view,replace){var u='?view='+view;if(replace)location.replace(u);else location.href=u;}

/* intercept internal links for SPA nav */
document.addEventListener('click',function(e){
  var a=e.target.closest('a');if(!a)return;
  var href=a.getAttribute('href');if(!href)return;
  if(a.target==='_blank'||/^https?:\/\//.test(href)||href.indexOf('mailto:')===0)return;
  if(href==='/'||href.indexOf('?view=')===0){
    e.preventDefault();
    if(href==='/')history.pushState({},'',location.pathname);
    else history.pushState({},'',href);
    route();
  }
});
window.addEventListener('popstate',route);

function setActiveNav(view){
  document.querySelectorAll('#headerNav a,#bottomNav a').forEach(function(a){
    a.classList.toggle('active',a.dataset.view===view||(view==='home'&&a.dataset.view==='home'));
  });
}

/* ==================== Chrome (nav/footer) ==================== */
function buildChrome(){
  var menu=SET.menu||[];
  $('#headerNav').innerHTML=menu.map(function(m){return '<a data-view="'+m.id+'" href="?view='+m.id+'">'+esc(m[LANG])+'</a>';}).join('');
  var bn=[['home','house'],['live','broadcast'],['matches','calendar-event'],['news','newspaper'],['videos','play-btn']];
  $('#bottomNav').innerHTML=bn.map(function(b){var it=menu.filter(function(x){return x.id===b[0];})[0]||{};return '<a data-view="'+b[0]+'" href="?view='+b[0]+'"><i class="bi bi-'+b[1]+'"></i>'+esc(it[LANG]||b[0])+'</a>';}).join('');
  var soc=SET.social||{},socH='';
  [['facebook','facebook'],['twitter','twitter-x'],['youtube','youtube'],['telegram','telegram'],['instagram','instagram']].forEach(function(s){if(soc[s[0]])socH+='<a href="'+esc(soc[s[0]])+'" target="_blank" rel="noopener" aria-label="'+s[0]+'"><i class="bi bi-'+s[1]+'"></i></a>';});
  $('#footerCols').innerHTML=
    '<div><h4>'+esc(SET.site['name_'+LANG])+'</h4><p style="color:var(--muted);font-size:13px">'+esc(SET.site['slogan_'+LANG])+'</p><div class="social">'+socH+'</div></div>'
    +'<div><h4>'+(LANG==='en'?'Sections':'الأقسام')+'</h4>'+menu.slice(0,6).map(function(m){return '<a href="?view='+m.id+'">'+esc(m[LANG])+'</a>';}).join('')+'</div>'
    +'<div><h4>'+(LANG==='en'?'Site':'الموقع')+'</h4><a href="?view=about">'+(LANG==='en'?'About':'من نحن')+'</a><a href="?view=contact">'+(LANG==='en'?'Contact':'اتصل بنا')+'</a><a href="?view=privacy">'+(LANG==='en'?'Privacy':'الخصوصية')+'</a></div>';
  $('#footerCopy').innerHTML='© '+new Date().getFullYear()+' '+esc(SET.site['name_'+LANG])+' · '+(LANG==='en'?'All rights reserved':'جميع الحقوق محفوظة');
}

/* ==================== Theme ==================== */
function applyTheme(){
  var saved=localStorage.getItem('q_theme');
  var mode=saved||(SET.theme&&SET.theme.dark_mode)||'auto';
  var dark = mode==='dark' || (mode==='auto'&&window.matchMedia&&window.matchMedia('(prefers-color-scheme:dark)').matches);
  document.documentElement.setAttribute('data-theme',dark?'dark':'light');
  var b=$('#themeBtn i');if(b)b.className='bi bi-'+(dark?'sun':'moon-stars');
  var tc=$('meta[name="theme-color"]');if(tc)tc.content=dark?'#0b1220':'#0d9488';
}
$('#themeBtn').onclick=function(){var cur=document.documentElement.getAttribute('data-theme');localStorage.setItem('q_theme',cur==='dark'?'light':'dark');applyTheme();};

/* ==================== Analytics / verification injection ==================== */
function injectAnalytics(){
  var a=SET.analytics||{};
  if(a.ga4){var s=document.createElement('script');s.async=true;s.src='https://www.googletagmanager.com/gtag/js?id='+a.ga4;document.head.appendChild(s);
    window.dataLayer=window.dataLayer||[];window.gtag=function(){dataLayer.push(arguments);};gtag('js',new Date());gtag('config',a.ga4);}
  if(a.gtm){var g=document.createElement('script');g.async=true;g.src='https://www.googletagmanager.com/gtm.js?id='+a.gtm;document.head.appendChild(g);}
  var ads=SET.ads||{};
  if(ads.adsense_client){var ad=document.createElement('script');ad.async=true;ad.crossOrigin='anonymous';
    ad.src='https://pagead2.googlesyndication.com/pagead/js/adsbygoogle.js?client='+ads.adsense_client;document.head.appendChild(ad);
    if(ads.auto_ads){var ai=document.createElement('script');ai.textContent='(adsbygoogle=window.adsbygoogle||[]).push({google_ad_client:"'+ads.adsense_client+'",enable_page_level_ads:true});';document.head.appendChild(ai);}}
  var v=SET.verification||{};
  [['google','google-site-verification'],['bing','msvalidate.01'],['yandex','yandex-verification'],['facebook','facebook-domain-verification']].forEach(function(x){
    if(v[x[0]]){var m=document.createElement('meta');m.name=x[1];m.content=v[x[0]];document.head.appendChild(m);}});
}

/* ==================== PWA ==================== */
function initPWA(){
  var mani={name:SET.site['name_'+LANG],short_name:'Qamhad',start_url:'/',display:'standalone',background_color:'#0b1220',theme_color:'#0d9488',dir:'rtl',lang:LANG,
    icons:[{src:API+'/assets/icon.svg',sizes:'any',type:'image/svg+xml',purpose:'any maskable'}]};
  var blob=new Blob([JSON.stringify(mani)],{type:'application/manifest+json'});
  var link=document.createElement('link');link.rel='manifest';link.href=URL.createObjectURL(blob);document.head.appendChild(link);
  if('serviceWorker' in navigator){navigator.serviceWorker.register('/sw.js').catch(function(){});}
  window.addEventListener('beforeinstallprompt',function(e){e.preventDefault();window._pwa=e;});
}

/* ==================== bind static UI ==================== */
$('#searchBtn').onclick=openSearch;
$('#searchClose').onclick=closeSearch;
$('#playerClose').onclick=closePlayer;
$('#playerModal').addEventListener('click',function(e){if(e.target===this)closePlayer();});
$('#searchInput').addEventListener('input',function(){doSearch(this.value.trim());});
$('#searchInput').addEventListener('keydown',function(e){if(e.key==='Enter'){var t=this.value.trim();if(t.length>=2)pushHistory(t);}});
$('#searchResults').addEventListener('click',function(e){
  var h=e.target.closest('.hist');if(h){$('#searchInput').value=h.dataset.term;doSearch(h.dataset.term);return;}
  var a=e.target.closest('a.suggest');if(a){closeSearch();}
});

/* ==================== boot ==================== */
applyTheme();
if(window.matchMedia)window.matchMedia('(prefers-color-scheme:dark)').addEventListener('change',function(){if(!localStorage.getItem('q_theme'))applyTheme();});

api('settings.php').then(function(r){
  SET=r.data||{};
  if(!SET.site)SET.site={name_ar:'قمهد لايف',name_en:'Qamhad Live',slogan_ar:'',slogan_en:'',blog_url:location.origin,email:'info@qamhad.com'};
  // apply theme colors
  if(SET.theme){var rt=document.documentElement.style;rt.setProperty('--primary',SET.theme.primary);rt.setProperty('--primary-dark',SET.theme.secondary);rt.setProperty('--accent',SET.theme.accent);}
  buildChrome();applyTheme();injectAnalytics();initPWA();
  route();refreshLiveBar();setInterval(refreshLiveBar,60000);
}).catch(function(){
  SET={site:{name_ar:'قمهد لايف',name_en:'Qamhad Live',slogan_ar:'',slogan_en:'',blog_url:location.origin,email:'info@qamhad.com'},menu:[
    {id:'home',ar:'الرئيسية',en:'Home'},{id:'live',ar:'مباشر',en:'Live'},{id:'matches',ar:'المباريات',en:'Matches'},
    {id:'leagues',ar:'البطولات',en:'Leagues'},{id:'news',ar:'الأخبار',en:'News'},{id:'videos',ar:'فيديو',en:'Videos'},{id:'channels',ar:'القنوات',en:'TV'}
  ],featured_leagues:[]};
  buildChrome();route();toast(LANG==='en'?'API offline — check api.qamhad.com':'تعذّر الاتصال بالخادم');
});

})();
